const SKIP_DOMAINS = [
  'myshopify.com', 'shopify.com', 'preview.shopify.com',
  'reddit.com', 'youtube.com', 'wikipedia.org',
  'twitter.com', 'facebook.com', 'instagram.com', 'linkedin.com',
  'google.com', 'amazon.de', 'ebay.de', 'otto.de', 'zalando.de',
  'trustpilot.com', 'ionos.de', 'wix.com', 'jimdo.com', 'wordpress.com',
  'indeed.de', 'stepstone.de', 'jobs.de'
];

const BUSINESS_MARKERS = ['gmbh', 'ug ', 'e.k.', 'inhaber'];
const ECOMMERCE_MARKERS = ['versandkosten', 'warenkorb', 'widerrufsbelehrung', 'shopify'];
const BFSG_MARKERS = ['barrierefreiheit', 'wcag', 'bfsg'];

const INDUSTRY_MAP = {
  mode: 'Mode', fashion: 'Mode',
  beauty: 'Beauty', kosmetik: 'Beauty',
  sport: 'Sport', fitness: 'Sport', outdoor: 'Outdoor',
  schmuck: 'Schmuck',
  wohnen: 'Wohnen', moebel: 'Wohnen',
  elektronik: 'Elektronik',
  kueche: 'Kueche', haushalt: 'Kueche',
  gesundheit: 'Gesundheit',
  baby: 'Baby', kinder: 'Baby',
  haustier: 'Haustier',
  gaming: 'Gaming'
};

function extractCategory(query) {
  const q = query.toLowerCase();
  for (const [key, val] of Object.entries(INDUSTRY_MAP)) {
    if (q.includes(key)) return val;
  }
  return 'Allgemein';
}

function hasAny(text, markers) {
  const lower = text.toLowerCase();
  return markers.some(function(m) { return lower.includes(m); });
}

const items = [];
const seen = new Set();

for (const inputItem of $input.all()) {
  const response = inputItem.json;
  if (!response.organic_results) continue;

  const query = (response.search_parameters && response.search_parameters.q) ? response.search_parameters.q : '';
  const isGoldenQuery = query.toLowerCase().includes('barrierefreiheit');
  const category = extractCategory(query);

  for (const result of response.organic_results) {
    if (!result.link) continue;
    try {
      const u = new URL(result.link);
      const domain = u.hostname.replace(/^www\./, '');
      if (!domain.endsWith('.de')) continue;
      if (SKIP_DOMAINS.some(function(s) { return domain.includes(s); })) continue;
      if (seen.has(domain)) continue;

      const text = (result.title || '') + ' ' + (result.snippet || '');
      const hasBusiness = hasAny(text, BUSINESS_MARKERS);
      const hasEcommerce = hasAny(text, ECOMMERCE_MARKERS);
      const mentionsBfsg = isGoldenQuery || hasAny(text, BFSG_MARKERS);

      if (!hasBusiness && !hasEcommerce) continue;

      seen.add(domain);
      items.push({
        json: {
          brand: result.title || domain,
          domain: domain,
          url: 'https://' + domain,
          category: mentionsBfsg ? 'BfSG-Aware' : category,
          status: mentionsBfsg ? 'BfSG-Aware' : 'New',
          description: result.snippet || ''
        }
      });
    } catch (e) {}
  }
}

return items.length ? items : [{ json: { _skip: true } }];

const seen = new Set();
const unique = [];

for (const item of $input.all()) {
  const lead = item.json;
  if (lead._skip || !lead.domain) continue;
  if (seen.has(lead.domain)) continue;
  seen.add(lead.domain);
  unique.push(lead);
}

return unique.map(function(l) { return { json: l }; });
